mapper.update:
UPDATE t_material_customs_broker
SET deleted_flag = #{deletedFlag}
WHERE customs_broker_id = #{customsBrokerId}

mapper.select:
SELECT *
FROM t_material_customs_broker
WHERE customs_broker_code = #{customsBrokerCode}
AND deleted_flag = #{deletedFlag}

    AND customs_broker_id != #{excludeCustomsBrokerId}

SELECT cb.*
FROM t_material_customs_broker cb

    cb.deleted_flag = #{queryForm.deletedFlag}

        AND (INSTR(cb.customs_broker_name,#{queryForm.keywords}) OR INSTR(cb.customs_broker_short_name,#{queryForm.keywords})
        OR INSTR(cb.customs_broker_code,#{queryForm.keywords}) OR INSTR(cb.contact,#{queryForm.keywords})
        OR INSTR(cb.contact_phone,#{queryForm.keywords}) OR INSTR(cb.create_user_name,#{queryForm.keywords}))


        AND DATE_FORMAT(cb.create_time, '%Y-%m-%d') >= #{queryForm.startTime}


        AND DATE_FORMAT(cb.create_time, '%Y-%m-%d') <= #{queryForm.endTime}


        AND cb.disabled_flag = #{queryForm.disabledFlag}



    ORDER BY cb.create_time DESC

SELECT cb.*
FROM t_material_customs_broker cb
WHERE cb.customs_broker_id = #{customsBrokerId}
  AND cb.deleted_flag = #{deletedFlag}
